<template><view class="page"><xy-header title="我的预约"/><view class="wrap"><view v-for="item in records" :key="item.reservationNo" class="card" @click="detail(item)"><text>{{item.reservationDate}} {{item.startTime}}-{{item.endTime}}</text><text>{{item.storeName}} · {{item.zoneName}}{{item.seatCode}}</text><text class="status">{{labels[item.status]||item.status}}</text></view><view v-if="!records.length" class="empty">暂无预约记录</view></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{records:[],labels:{BOOKED:'待到场',CHECKED_IN:'已签到',CANCELED:'已取消',NO_SHOW:'爽约'}}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.records=await appRequest({url:'/app/reservations'})}catch(e){showRequestError(e)}},detail(item){uni.navigateTo({url:`/pages/reserve/detail?reservationNo=${item.reservationNo}`})}}}</script><style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{display:flex;flex-direction:column;gap:12rpx;margin-bottom:18rpx;padding:26rpx;border-radius:20rpx;background:#fff}.status{color:var(--xy-primary)}.empty{padding:120rpx;text-align:center;color:var(--xy-muted)}</style>
